(() => {
  const PRODUCT_IMAGES = {'assets/products/biotica-refill.jpg':'data:image/jpeg;base64,','assets/products/fiber-refill.jpg':'data:image/jpeg;base64,','assets/products/magnesium-refill.jpg':'data:image/jpeg;base64,','assets/products/multi-refill.jpg':'data:image/jpeg;base64,','assets/products/welkomstpakket.jpg':'data:image/jpeg;base64,'};
  const replaceProductImage = (img) => {
    const key = (img.getAttribute('src') || '').split('?')[0].replace(/^\.\//, '');
    if (PRODUCT_IMAGES[key] && img.src !== PRODUCT_IMAGES[key]) img.src = PRODUCT_IMAGES[key];
  };
  const refreshProducts = () => document.querySelectorAll('img').forEach(replaceProductImage);
  refreshProducts();
  new MutationObserver(refreshProducts).observe(document.body, {childList:true, subtree:true});
})();
